output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?taxSource WHERE {
  wd:Q2723740 rdfs:label ?taxSource
  FILTER(LANG(?taxSource) = 'en')
}

